"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[4106],{14505:e=>{e.exports=JSON.parse('{"functions":[{"name":"GetPosition","desc":"Returns the bullet\'s current world-space position using the analytic\\nkinematic formula `P(t) = Origin + V\u2080t + \xbdAt\xb2`. Always accurate to the\\ncurrent simulation time regardless of when in the frame it is called.","params":[],"returns":[{"desc":"","lua_type":"Vector3"}],"function_type":"method","source":{"line":61,"path":"docs/VetraCast.lua"}},{"name":"GetVelocity","desc":"Returns the bullet\'s current velocity vector. The magnitude of this vector\\nis the current speed in studs per second.","params":[],"returns":[{"desc":"","lua_type":"Vector3"}],"function_type":"method","source":{"line":69,"path":"docs/VetraCast.lua"}},{"name":"GetAcceleration","desc":"Returns the constant acceleration vector for the active trajectory segment.\\nThis is the pre-computed sum of gravity, extra acceleration, wind, and\\nany initial drag deceleration for this segment, not `workspace.Gravity` alone.","params":[],"returns":[{"desc":"","lua_type":"Vector3"}],"function_type":"method","source":{"line":78,"path":"docs/VetraCast.lua"}},{"name":"SetPosition","desc":"Teleports the bullet to a new world-space position without changing its\\nvelocity or acceleration. Opens a new trajectory segment if simulation\\ntime has already elapsed on the current one.","params":[{"name":"position","desc":"","lua_type":"Vector3"}],"returns":[],"function_type":"method","source":{"line":89,"path":"docs/VetraCast.lua"}},{"name":"SetVelocity","desc":"Changes the bullet\'s velocity to the given vector. Opens a new trajectory\\nsegment if needed.\\n\\n:::tip\\nCall [VetraCast:ResetBounceState] after a sharp velocity change to prevent\\nthe corner-trap detector from falsely triggering on the new trajectory.\\n:::","params":[{"name":"velocity","desc":"","lua_type":"Vector3"}],"returns":[],"function_type":"method","source":{"line":102,"path":"docs/VetraCast.lua"}},{"name":"SetAcceleration","desc":"Replaces the bullet\'s constant acceleration for future simulation. Because\\nacceleration is constant within a segment, this always opens a new segment\\nunless the current one has zero elapsed time.","params":[{"name":"acceleration","desc":"","lua_type":"Vector3"}],"returns":[],"function_type":"method","source":{"line":111,"path":"docs/VetraCast.lua"}},{"name":"AddPosition","desc":"Translates the bullet by an offset in world space. Equivalent to\\n`SetPosition(GetPosition() + offset)`.","params":[{"name":"offset","desc":"","lua_type":"Vector3"}],"returns":[],"function_type":"method","source":{"line":119,"path":"docs/VetraCast.lua"}},{"name":"AddVelocity","desc":"Adds a delta to the bullet\'s current velocity. Useful for impulse effects\\nsuch as explosion knockback applied mid-flight.","params":[{"name":"delta","desc":"","lua_type":"Vector3"}],"returns":[],"function_type":"method","source":{"line":127,"path":"docs/VetraCast.lua"}},{"name":"AddAcceleration","desc":"Adds a delta to the bullet\'s constant acceleration. Useful for variable\\nforces that build up over time via repeated calls, such as thrust or dynamic wind.","params":[{"name":"delta","desc":"","lua_type":"Vector3"}],"returns":[],"function_type":"method","source":{"line":135,"path":"docs/VetraCast.lua"}},{"name":"Pause","desc":"Pauses simulation for this cast. The solver skips it entirely each frame\\nuntil [VetraCast:Resume] is called. `TotalRuntime` does not advance while\\npaused, so the bullet resumes from exactly the same kinematic state.\\n\\nUseful for cutscenes, slow-motion effects, or deferred spawning patterns.","params":[],"returns":[],"function_type":"method","source":{"line":146,"path":"docs/VetraCast.lua"}},{"name":"Resume","desc":"Resumes a previously paused cast. Has no effect if the cast is not paused.","params":[],"returns":[],"function_type":"method","source":{"line":151,"path":"docs/VetraCast.lua"}},{"name":"IsPaused","desc":"Returns whether this cast is currently paused.","params":[],"returns":[{"desc":"","lua_type":"boolean"}],"function_type":"method","source":{"line":158,"path":"docs/VetraCast.lua"}},{"name":"ResetBounceState","desc":"Resets the corner-trap detector state for this cast.\\n\\nClears `BouncePositionHistory`, `LastBounceTime`, and `VelocityDirectionEMA`\\nback to their initial values.\\n\\nCall this after any programmatic mid-flight velocity change (e.g.\\n`SetVelocity`, `AddVelocity`) that deliberately reverses or sharply\\nredirects the bullet. Without this, the EMA-based corner-trap detector may\\nfalsely terminate the cast on the next bounce.","params":[],"returns":[],"function_type":"method","source":{"line":173,"path":"docs/VetraCast.lua"}},{"name":"ResetPierceState","desc":"Resets the pierce state for this cast.\\n\\nClears `PiercedInstances`, resets `PierceCount` to 0, and restores the\\noriginal `FilterDescendantsInstances` on the cast\'s `RaycastParams`.\\n\\nTypically called from an `OnBounce` handler when `ResetPierceOnBounce`\\nis not sufficient, for example, if you only want to reset pierce state\\nafter specific bounces rather than all of them.","params":[],"returns":[],"function_type":"method","source":{"line":185,"path":"docs/VetraCast.lua"}},{"name":"Terminate","desc":"Terminates this cast immediately.\\n\\nEquivalent to calling `context:Terminate()` on the linked [BulletContext].\\nFires `OnTerminated`. Calling `Terminate` on an already-dead cast is a no-op.","params":[],"returns":[],"function_type":"method","source":{"line":193,"path":"docs/VetraCast.lua"}}],"properties":[{"name":"Alive","desc":"`true` while the cast is being simulated. Set to `false` as the very\\nfirst action in termination so re-entrant calls are no-ops.","lua_type":"boolean","readonly":true,"source":{"line":31,"path":"docs/VetraCast.lua"}},{"name":"Paused","desc":"When `true`, the solver skips this cast entirely each frame.\\n`TotalRuntime` does not advance while paused, so resumption picks up\\nseamlessly from the exact state the bullet was in when paused.\\n\\nUse [VetraCast:Pause] and [VetraCast:Resume] rather than writing this\\nfield directly.","lua_type":"boolean","source":{"line":43,"path":"docs/VetraCast.lua"}},{"name":"UserData","desc":"Free-form table for weapon-specific metadata. Shared with the linked\\n[BulletContext] and passed unchanged on every signal emission.","lua_type":"{[any]: any}","source":{"line":51,"path":"docs/VetraCast.lua"}}],"types":[],"name":"VetraCast","desc":"The internal representation of one in-flight projectile. Returned by\\n[Vetra:Fire] for callers that need to introspect or modify a bullet\\nmid-flight.\\n\\n:::warning Prefer BulletContext\\nWeapon scripts should interact with [BulletContext] rather than `VetraCast`\\ndirectly. `VetraCast` exposes internal solver state, mutating it outside\\nof the documented methods can produce physics errors that are difficult\\nto debug.\\n\\nThe methods below (`GetPosition`, `SetVelocity`, `Pause`, etc.) are safe\\nto call and are the intended way to read or modify a bullet mid-flight\\nfrom within signal handlers.\\n:::","source":{"line":19,"path":"docs/VetraCast.lua"}}')}}]);